"use client";
import React, { useEffect, useState } from 'react';
import Image from 'next/image';
import Link from 'next/link';
import { Cpu, Briefcase, ChevronLeft, ChevronRight } from 'lucide-react';

import { useInView, getFadeUpClasses, getStaggerStyle } from '@/lib/animations';

export default function About() {
  const [setRef, inView] = useInView();
  const [currentImageIndex, setCurrentImageIndex] = useState(0);

  const images = [
    "/co-founders.jpg",
    "/about-img-2.jpg", // Placeholder paths for the additional images
    "/about-img-3.jpg"  // Will fall back natively or user will provide them
  ];

  const prevImage = () => {
    setCurrentImageIndex((prev) => (prev - 1 + images.length) % images.length);
  };

  const nextImage = () => {
    setCurrentImageIndex((prev) => (prev + 1) % images.length);
  };

  return (
    <section id="about" className="relative py-24 lg:py-32 bg-transparent overflow-hidden z-0">
      
      {/* Required Animation Easing */}
      <style dangerouslySetInnerHTML={{ __html: `
        .cubic-out {
          transition-timing-function: cubic-bezier(0.22, 1, 0.36, 1);
        }
      `}} />
      
      <div className="relative z-10 w-full max-w-7xl mx-auto px-4 sm:px-6 lg:px-8" ref={setRef as any}>
        <div className="grid grid-cols-1 lg:grid-cols-12 gap-12 lg:gap-16 items-center">
          
          {/* ----- LEFT COLUMN: Narrative & Metrics ----- */}
          <div 
            className={`lg:col-span-7 flex flex-col justify-center order-2 lg:order-1 pt-8 lg:pt-0 ${getFadeUpClasses(inView, 'translate-y-12')}`}
            style={getStaggerStyle(inView, 0)}
          >
            
            <div 
              className={`flex items-center gap-3 mb-6 ${getFadeUpClasses(inView, 'translate-y-6')}`}
              style={getStaggerStyle(inView, 1, 0)}
            >
              <div className="h-px w-6 bg-brand-600 rounded-full" />
              <h3 className="text-[12px] font-bold text-brand-900 uppercase tracking-widest font-sans">
                Who We Are
              </h3>
            </div>

            <h2 className={`text-3xl sm:text-4xl lg:text-[2.75rem] font-bold text-gray-900 mb-6 font-sans leading-[1.12] tracking-tight ${getFadeUpClasses(inView, 'translate-y-6')}`}
              style={getStaggerStyle(inView, 2, 0)}
            >
              Hardware precision meets <br className="hidden md:block"/>
              <span className="text-brand-900">software intelligence.</span>
            </h2>

            <div className="max-w-[600px] text-[15px] sm:text-base text-gray-600 font-poppins leading-relaxed mb-10 space-y-4">
              <p>
                As dedicated freelance IoT specialists based in Talisay City, Negros Occidental, we partner with visionaries and businesses to architect custom solutions from the ground up.
              </p>
              <p>
                From designing custom microcontroller circuits to deploying responsive cloud dashboards, our student-centered approach focuses on building robust ecosystems that seamlessly connect the physical world to actionable digital insights.
              </p>
            </div>

            {/* Metrics Row with Lucide Icons */}
            <div className="grid grid-cols-2 gap-4 md:gap-5 mb-10 max-w-[420px]">
              {/* Metric 1 */}
              <div className="group flex flex-col items-start border-l-[3px] border-gray-200 hover:border-brand-500 bg-gray-50/80 p-4 transition-colors duration-300">
                <div className="flex items-center justify-between w-full mb-1">
                  <span className="text-2xl sm:text-3xl font-bold text-gray-900 font-sans tracking-tight">10+</span>
                  <Cpu className="w-5 h-5 text-gray-400 group-hover:text-brand-500 transition-colors duration-300" strokeWidth={2} />
                </div>
                <div className="text-[11px] sm:text-xs text-gray-500 font-poppins font-semibold uppercase tracking-wider mt-1">
                  Projects Completed
                </div>
              </div>

              {/* Metric 2 */}
              <div className="group flex flex-col items-start border-l-[3px] border-gray-200 hover:border-brand-500 bg-gray-50/80 p-4 transition-colors duration-300">
                <div className="flex items-center justify-between w-full mb-1">
                  <span className="text-2xl sm:text-3xl font-bold text-gray-900 font-sans tracking-tight">2+</span>
                  <Briefcase className="w-5 h-5 text-gray-400 group-hover:text-brand-500 transition-colors duration-300" strokeWidth={2} />
                </div>
                <div className="text-[11px] sm:text-xs text-gray-500 font-poppins font-semibold uppercase tracking-wider mt-1">
                  Years Experience
                </div>
              </div>
            </div>

            <div>
              <a 
                href="#contact" 
                className="group relative inline-flex items-center justify-center gap-2.5 px-8 py-3.5 bg-brand-900 text-white text-[14.5px] font-medium font-poppins rounded-[8px] overflow-hidden transition-all duration-300 hover:bg-brand-700 active:scale-[0.98]"
              >
                <span>Contact Us</span>
                <svg className="w-4 h-4 transition-transform duration-300 group-hover:translate-x-1" fill="none" viewBox="0 0 24 24" strokeWidth="2.5" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" d="M13.5 4.5L21 12m0 0l-7.5 7.5M21 12H3" />
                </svg>
              </a>
            </div>
          </div>

          {/* ----- RIGHT COLUMN: Founders Photo Carousel ----- */}
          <div 
            className={`lg:col-span-5 relative order-1 lg:order-2 ${getFadeUpClasses(inView, 'translate-y-12')}`}
            style={getStaggerStyle(inView, 3, 0)}
          >
            <div className="relative p-2 md:p-2.5 bg-white border border-gray-100 shadow-[0_4px_24px_rgb(0,0,0,0.06)] rounded-xl isolate hover:-translate-y-1 transition-transform duration-500 group/carousel">
              <div className="relative aspect-[4/5] bg-gray-100 rounded-lg overflow-hidden isolate">
                
                {images.map((src, idx) => (
                  <Image 
                    key={src}
                    src={src} 
                    alt={`About 8K IoT Solutions Image ${idx + 1}`}
                    fill
                    sizes="(max-width: 768px) 100vw, 40vw"
                    className={`object-cover transition-opacity duration-700 ease-in-out ${idx === currentImageIndex ? 'opacity-100 z-10' : 'opacity-0 z-0'}`}
                    priority={idx === 0}
                  />
                ))}

                {/* Carousel Controls */}
                <div className="absolute inset-0 flex items-center justify-between p-3 opacity-0 group-hover/carousel:opacity-100 transition-opacity duration-300 z-20">
                  <button 
                    onClick={prevImage}
                    className="p-2 rounded-full bg-white/90 text-gray-800 hover:bg-white transition-all shadow-md backdrop-blur-sm hover:scale-105 active:scale-95 focus:outline-none"
                    aria-label="Previous image"
                  >
                    <ChevronLeft className="w-5 h-5" />
                  </button>
                  <button 
                    onClick={nextImage}
                    className="p-2 rounded-full bg-white/90 text-gray-800 hover:bg-white transition-all shadow-md backdrop-blur-sm hover:scale-105 active:scale-95 focus:outline-none"
                    aria-label="Next image"
                  >
                    <ChevronRight className="w-5 h-5" />
                  </button>
                </div>

                {/* Carousel Indicators (Dots) */}
                <div className="absolute bottom-4 left-0 right-0 flex justify-center gap-2 z-20">
                  {images.map((_, idx) => (
                    <button
                      key={idx}
                      onClick={() => setCurrentImageIndex(idx)}
                      aria-label={`Go to slide ${idx + 1}`}
                      className={`h-1.5 rounded-full transition-all duration-300 ${
                        idx === currentImageIndex 
                          ? 'w-4 bg-white shadow-sm' 
                          : 'w-1.5 bg-white/50 hover:bg-white/80'
                      }`}
                    />
                  ))}
                </div>

              </div>
            </div>
            
            <div className="absolute -inset-0 border border-brand-200 z-[-1] rounded-xl translate-x-3 translate-y-3 hidden md:block transition-transform duration-500 group-hover/carousel:translate-x-4 group-hover/carousel:translate-y-4" />
          </div>

        </div>
      </div>
    </section>
  );
}

"use client";
import Image from 'next/image';
import Link from 'next/link';
import { useEffect, useState } from 'react';
import { getFadeUpClasses, getStaggerStyle } from '@/lib/animations';

export default function Hero() {
  const [mounted, setMounted] = useState(false);
  
  useEffect(() => {
    setMounted(true);
  }, []);

  // Using the co-founders image for all slots to create the seamless vertical flow
  const scrollImages = ['/client.jpg', '/client.jpg', '/client.jpg', '/client.jpg'];

  return (
    <section id="home" className="relative min-h-[100vh] lg:min-h-[90vh] flex items-center pt-24 pb-16 overflow-hidden z-0 bg-transparent">
      <div className="w-full max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 relative z-10">
        <div className="grid grid-cols-1 lg:grid-cols-12 gap-12 lg:gap-8 items-start">
          
          {/* ----- LEFT COLUMN: Content Stack ----- */}
          {/* pt-8 and lg:pt-12 moves this stack higher up the page */}
          <div className="lg:col-span-6 flex flex-col items-start text-left pt-8 lg:pt-16 opacity-0 animate-heroPop">
            <h1 
              className={`font-sans font-bold text-4xl sm:text-5xl lg:text-[3.5rem] text-slate-900 tracking-tight leading-[1.12] mb-6 ${getFadeUpClasses(mounted, 'translate-y-8')}`}
              style={getStaggerStyle(mounted, 1)}
            >
              Building Ideas <br className="hidden sm:block" />
              <span className="text-brand-900">Into Reality</span>
            </h1>
            
            <p 
              className={`font-poppins font-normal text-slate-600 text-[15px] sm:text-[16px] leading-[1.7] max-w-[58ch] mb-10 ${getFadeUpClasses(mounted, 'translate-y-8')}`}
              style={getStaggerStyle(mounted, 2)}
            >
              We offer a range of hardware and software services, including device prototyping, system integration, and web-based solutions, tailored to help students and innovators bring their ideas to life.
            </p>
            
            <div 
              className={`flex flex-col sm:flex-row gap-4 w-full sm:w-auto ${getFadeUpClasses(mounted, 'translate-y-8')}`}
              style={getStaggerStyle(mounted, 3)}
            >
              <a 
                href="#contact" 
                className="group relative inline-flex items-center justify-center gap-2.5 px-8 py-3.5 bg-brand-900 text-white text-[15px] font-bold font-sans rounded-[6px] transition-all duration-300 hover:bg-brand-700 active:scale-[0.98] shadow-sm"
              >
                <span>Start a Project</span>
                <svg className="w-4 h-4 transition-transform duration-300 group-hover:translate-x-1" fill="none" viewBox="0 0 24 24" strokeWidth="2.5" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" d="M13.5 4.5L21 12m0 0l-7.5 7.5M21 12H3" />
                </svg>
              </a>

              <a 
                href="#services" 
                className="group inline-flex items-center justify-center gap-2.5 px-8 py-3.5 border-2 border-gray-200 bg-white text-gray-900 text-[15px] font-bold font-sans rounded-[6px] transition-all duration-300 hover:border-brand-600 hover:text-brand-600 active:scale-[0.98] shadow-sm"
              >
                <span>Explore Services</span>
              </a>
            </div>
          </div>

          {/* ----- RIGHT COLUMN: Asymmetric Scrolling Grid ----- */}
          <div 
            className={`lg:col-span-6 relative h-[500px] sm:h-[650px] w-full rounded-3xl overflow-hidden lg:ml-8 mt-12 lg:mt-0 ${getFadeUpClasses(mounted, 'translate-y-8')}`}
            style={getStaggerStyle(mounted, 2)}
          >
            
            {/* Gradient masks to ensure images don't look cut off at the edges */}
            <div className="absolute inset-x-0 top-0 h-32 bg-gradient-to-b from-white via-white/80 to-transparent z-20 pointer-events-none" />
            <div className="absolute inset-x-0 bottom-0 h-32 bg-gradient-to-t from-white via-white/80 to-transparent z-20 pointer-events-none" />

            {/* The Grid Container - Ensure co-founders.jpg is in /public folder */}
            <div className="grid grid-cols-2 gap-4 h-full transform -rotate-3 scale-110">
              
              {/* Column 1: Top to Bottom (Scroll Down) */}
              <div className="relative h-full overflow-hidden">
                <div className="flex flex-col gap-4 animate-scroll-down">
                  {scrollImages.map((src, idx) => (
                    <div key={`down-${idx}`} className="relative w-full aspect-[4/5] rounded-2xl overflow-hidden border border-gray-100 shadow-sm bg-gray-50">
                      <Image 
                        src={src} 
                        alt="Work Showcase" 
                        fill 
                        className="object-cover"
                        sizes="(max-width: 768px) 50vw, 33vw"
                        priority={idx < 2} 
                      />
                    </div>
                  ))}
                </div>
              </div>

              {/* Column 2: Bottom to Top (Scroll Up) */}
              <div className="relative h-full overflow-hidden">
                <div className="flex flex-col gap-4 animate-scroll-up">
                  {scrollImages.map((src, idx) => (
                    <div key={`up-${idx}`} className="relative w-full aspect-[4/5] rounded-2xl overflow-hidden border border-gray-100 shadow-sm bg-gray-50">
                      <Image 
                        src={src} 
                        alt="Work Showcase" 
                        fill 
                        className="object-cover"
                        sizes="(max-width: 768px) 50vw, 33vw"
                        priority={idx < 2}
                      />
                    </div>
                  ))}
                </div>
              </div>

            </div>
          </div>

        </div>
      </div>
    </section>
  );
}

"use client";
import React, { useEffect, useState } from 'react';
import { Search, LayoutTemplate, Cpu, Rocket } from 'lucide-react';

import { useInView, getFadeUpClasses, getStaggerStyle } from '@/lib/animations';

const steps = [
  {
    number: '01',
    title: 'Discovery',
    description: 'Understanding the project idea, requirements, and constraints.',
    details: 'We dive deep into your vision, target audience, and technical feasibility to ensure a solid foundation from day one.',
    icon: Search
  },
  {
    number: '02',
    title: 'Architecture',
    description: 'Designing the hardware components and software system structure.',
    details: 'Creating custom schematic blueprints, selecting optimal microcontrollers, and mapping out the cloud database architecture.',
    icon: LayoutTemplate
  },
  {
    number: '03',
    title: 'Prototyping',
    description: 'Rapid hardware and software development to validate the concept.',
    details: 'Iterative building of physical electronics and writing functional code to bring the underlying concept to life quickly.',
    icon: Cpu
  },
  {
    number: '04',
    title: 'Deployment',
    description: 'Testing, refining, and delivering the final working system.',
    details: 'Rigorous real-world field testing, performance polish, and finally handing over a production-ready IoT solution.',
    icon: Rocket
  },
];

export default function Process() {
  const [setRef, inView] = useInView({ threshold: 0.1 });

  return (
    <section id="process" className="relative w-full pt-8 pb-24 lg:pt-12 lg:pb-32 bg-transparent text-zinc-900 overflow-hidden z-0 border-t border-zinc-50 border-b">
      
      {/* 1. Subtle Premium Background Layers */}
      {/* Soft Aurora Glows */}
      <div className="absolute top-0 right-1/4 w-[600px] h-[600px] bg-brand-50/60 rounded-full blur-[120px] pointer-events-none" />
      <div className="absolute bottom-0 left-1/4 w-[500px] h-[500px] bg-blue-50/50 rounded-full blur-[100px] pointer-events-none" />

      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 relative z-10" ref={setRef as any}>
        
        {/* Section Header */}
        <div 
          className={`text-center mb-16 md:mb-24 ${getFadeUpClasses(inView, 'translate-y-8')}`}
          style={getStaggerStyle(inView, 0)}
        >
          <div className="inline-flex items-center gap-2 px-3 py-1.5 rounded-full bg-brand-50 border border-brand-100 mb-6 font-poppins text-xs font-semibold text-brand-600 uppercase tracking-widest">
            <span className="w-1.5 h-1.5 rounded-full bg-brand-500 animate-pulse" />
            Our Process
          </div>
          <h2 className="text-3xl md:text-[2.5rem] font-sans font-bold tracking-tight text-zinc-900 mb-5 leading-tight">
            How We Build
          </h2>
          <p className="text-[15px] md:text-base text-zinc-500 font-poppins max-w-2xl mx-auto leading-relaxed">
            From concept to working systems. Our workflow combines rigorous hardware engineering with modern, scalable software development practices.
          </p>
        </div>

        {/* Timeline Container */}
        <div className="relative mt-12 lg:mt-20">
          
          {/* Connecting Line with Glowing Endpoints */}
          <div className="absolute left-[34px] lg:left-0 top-[34px] lg:top-[34px] lg:right-0 bottom-0 lg:bottom-auto w-[2px] lg:w-full lg:h-[2px] bg-zinc-100 -z-10 isolate">
            {/* Glowing endpoints (desktop only) */}
            <div className="hidden lg:block absolute left-0 top-1/2 -translate-y-1/2 w-4 h-[2px] bg-gradient-to-r from-transparent to-brand-300" />
            <div className="hidden lg:block absolute right-0 top-1/2 -translate-y-1/2 w-4 h-[2px] bg-gradient-to-l from-transparent to-brand-300" />
            
            {/* Moving glow effect along the line */}
            <div className="absolute top-0 left-0 w-full h-[30%] lg:w-[30%] lg:h-full bg-gradient-to-b lg:bg-gradient-to-r from-transparent via-brand-400/30 to-transparent animate-shimmer" />
          </div>

          <div className="grid grid-cols-1 lg:grid-cols-4 gap-8 lg:gap-6 relative z-10 pt-2 lg:pt-0">
            {steps.map((step, index) => {
              const Icon = step.icon;
              return (
                <div 
                  key={step.number}
                  className={`group relative flex lg:flex-col items-start lg:items-start gap-6 lg:gap-8 ${getFadeUpClasses(inView, 'translate-y-12')}`}
                  style={getStaggerStyle(inView, index + 1, 0)}
                >
                  {/* Node Point */}
                  <div className="relative z-20 shrink-0 mt-0 lg:mt-0 lg:mx-auto">
                    <div className="w-[68px] h-[68px] flex items-center justify-center bg-white border-2 border-zinc-100 rounded-full shadow-[0_4px_12px_rgba(0,0,0,0.03)] group-hover:scale-110 group-hover:border-brand-200 group-hover:shadow-[0_8px_24px_rgba(59,130,246,0.12)] transition-all duration-500 ease-out relative isolate">
                       <span className="font-poppins font-bold text-zinc-400 text-sm group-hover:text-brand-600 transition-colors duration-300">
                          {step.number}
                       </span>
                       {/* Subtle outer ping on hover */}
                       <div className="absolute inset-0 rounded-full border border-brand-400 opacity-0 group-hover:animate-ping transition-opacity duration-300 -z-10" />
                    </div>
                  </div>

                  {/* Content Panel (Glassmorphism Card) */}
                  <div className="relative flex-1 w-full bg-white/70 hover:bg-white backdrop-blur-md border border-zinc-100 hover:border-brand-100/60 p-6 md:p-8 rounded-2xl md:rounded-3xl shadow-[0_4px_20px_rgba(0,0,0,0.02)] hover:shadow-[0_12px_30px_rgba(0,0,0,0.05)] transition-all duration-500 hover:-translate-y-1 ease-out overflow-hidden">
                    
                    {/* Oversized Background Number anchor */}
                    <div className="absolute -top-6 -right-4 text-[7rem] md:text-[9rem] font-poppins font-bold text-zinc-50 -z-10 select-none group-hover:text-brand-50/50 transition-colors duration-500 pointer-events-none tracking-tighter leading-none">
                      {step.number}
                    </div>
                    
                    {/* Step Icon */}
                    <div className="w-10 h-10 rounded-xl bg-zinc-50 border border-zinc-100 flex items-center justify-center mb-5 group-hover:bg-brand-50 group-hover:border-brand-100 transition-colors duration-500 shadow-sm">
                      <Icon className="w-5 h-5 text-zinc-400 group-hover:text-brand-500 transition-colors duration-500" strokeWidth={2} />
                    </div>
                    
                    <h3 className="text-xl font-poppins font-bold text-zinc-900 mb-3 group-hover:text-brand-900 transition-colors duration-300 tracking-tight">
                      {step.title}
                    </h3>
                    
                    <p className="text-[14px] text-zinc-600 font-medium leading-relaxed mb-4">
                      {step.description}
                    </p>
                    
                    <p className="text-[13px] text-zinc-500/90 leading-relaxed font-poppins border-t border-zinc-100 pt-4 group-hover:border-brand-50 transition-colors duration-500">
                      {step.details}
                    </p>
                  </div>
                </div>
              );
            })}
          </div>
        </div>

      </div>
    </section>
  );
}

'use client';

import { useEffect, useRef } from 'react';
import { usePathname, useRouter } from 'next/navigation';

export default function SectionUrlSync() {
  const pathname = usePathname();
  const router = useRouter();
  const observerRef = useRef<IntersectionObserver | null>(null);
  const initialScrollHandled = useRef(false);

  // 1. Handle initial load scrolling
  useEffect(() => {
    if (initialScrollHandled.current) return;

    // We only care if we loaded distinctly at a known section path 
    const isSectionPath = ['/about', '/services', '/contact'].includes(pathname);

    if (isSectionPath) {
      initialScrollHandled.current = true;
      const targetId = pathname.slice(1); // removes the '/'

      // Wait for DOM to finish hydration before scrolling
      setTimeout(() => {
        const element = document.getElementById(targetId);
        if (element) {
          const navbarOffset = 100;
          const elementPosition = element.getBoundingClientRect().top;
          const offsetPosition = elementPosition + window.scrollY - navbarOffset;
          window.scrollTo({
            top: offsetPosition,
            behavior: 'smooth' // or 'instant' if immediate jump is preferred
          });
        }
      }, 500);
    } else {
      initialScrollHandled.current = true;
    }
  }, [pathname]);

  // 2. Handle scroll observing
  useEffect(() => {
    // Only run on the root/home base view
    if (pathname.startsWith('/admin') || pathname.startsWith('/projects/')) return;

    const sections = ['home', 'about', 'services', 'contact'];

    const handleIntersect = (entries: IntersectionObserverEntry[]) => {
      // Find the most prominent intersecting entry
      const visibleEntries = entries.filter((entry) => entry.isIntersecting);

      if (visibleEntries.length > 0) {
        // Find the entry that has the largest intersection ratio
        const bestEntry = visibleEntries.reduce((prev, current) => 
          prev.intersectionRatio > current.intersectionRatio ? prev : current
        );

        const currentHash = window.location.pathname;
        const targetPath = bestEntry.target.id === 'home' ? '/' : `/${bestEntry.target.id}`;

        // Only update if it actually changed and we aren't rapidly scrolling
        if (currentHash !== targetPath) {
           window.history.replaceState(null, '', targetPath);
        }
      }
    };

    observerRef.current = new IntersectionObserver(handleIntersect, {
      root: null,
      rootMargin: '-20% 0px -40% 0px', // Triggers when section is roughly in the middle 60% of viewport
      threshold: [0, 0.25, 0.5, 0.75, 1], // Provide multiple thresholds for better detection
    });

    sections.forEach((id) => {
      const element = document.getElementById(id);
      if (element) {
        observerRef.current?.observe(element);
      }
    });

    return () => {
      if (observerRef.current) {
        observerRef.current.disconnect();
      }
    };
  }, [pathname]);

  return null;
}

